exercises.solution_code:
#include <iostream>

int main() {
    if constexpr (sizeof(int) == 4) {
        std::cout << "int is 4 bytes\n";
    } else if constexpr (sizeof(int) == 2) {
        std::cout << "int is 2 bytes\n";
    } else {
        std::cout << "int is an unusual size\n";
    }

    if constexpr (sizeof(double) == 8) {
        std::cout << "double is 8 bytes\n";
    } else {
        std::cout << "double is not 8 bytes\n";
    }

    return 0;
}

