exercises.solution_code:
#include <iostream>

int main() {
    constexpr int mode{ 2 };

    if constexpr (mode == 1) {
        std::cout << "Mode: Debug\n";
        std::cout << "Verbose logging enabled\n";
    } else if constexpr (mode == 2) {
        std::cout << "Mode: Release\n";
        std::cout << "Optimizations enabled\n";
    } else if constexpr (mode == 3) {
        std::cout << "Mode: Test\n";
        std::cout << "Test harness active\n";
    } else {
        std::cout << "Mode: Unknown\n";
        std::cout << "No special configuration\n";
    }

    return 0;
}
